@namespace CheckoutWizard.Components

<div class="checkout-wizard">
    @if (_step == Step.Shipping)
    {
        <ShippingStep Shipping="@_order.Shipping"
                      OnNext="@HandleShippingComplete" />
    }
    else
    {
        <PaymentStep Payment="@_order.Payment"
                     OnBack="@HandleBackToShipping"
                     OnPlaceOrder="@HandlePlaceOrder" />
    }
</div>

@code {
    private enum Step { Shipping, Payment }

    private Step _step = Step.Shipping;
    private readonly Order _order = new();

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void HandleShippingComplete()
    {
        _step = Step.Payment;
    }

    private void HandleBackToShipping()
    {
        _step = Step.Shipping;
    }

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@namespace CheckoutWizard.Components
@implements IDisposable
@inject IAddressValidator AddressValidator

<h3>Shipping Information</h3>

<div class="form-group">
    <label for="name">Name</label>
    <input id="name" @bind="Shipping.Name" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label for="address">Address</label>
    <input id="address" @bind="Shipping.Address" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label for="city">City</label>
    <input id="city" @bind="Shipping.City" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label for="zip">Zip Code</label>
    <input id="zip" @bind="Shipping.ZipCode" disabled="@_isValidating" />
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="validation-error">@_errorMessage</div>
}

<button disabled="@_isValidating" @onclick="HandleNext">
    @if (_isValidating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task HandleNext()
    {
        _errorMessage = null;

        // Cancel any in-flight validation before starting a new one.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — either the user re-submitted or the component
            // was disposed. Nothing to do.
        }
        finally
        {
            // Only clear the spinner if this is still the active validation pass.
            if (!token.IsCancellationRequested)
            {
                _isValidating = false;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

